#!/usr/bin/env python3

import argparse
import os
import shutil
import subprocess
import sys
import zipfile
from pathlib import Path


def run(cmd, cwd=None):
    print("+", " ".join(cmd))
    subprocess.run(cmd, cwd=cwd, check=True)


def install_dependencies(project_dir):
    requirements = project_dir / "requirements.txt"
    if requirements.exists():
        run([sys.executable, "-m", "pip", "install", "--disable-pip-version-check", "-q", "-r", str(requirements)])
    else:
        print("requirements.txt not found, skipping dependency installation")


def run_tests(project_dir):
    if (project_dir / "pytest.ini").exists() or (project_dir / "tests").exists():
        run([sys.executable, "-m", "pytest", "-q"], cwd=project_dir)
    else:
        print("No tests detected, skipping test step")


def should_exclude(path):
    parts = set(path.parts)
    excluded_names = {
        ".git",
        ".github",
        ".venv",
        "venv",
        "__pycache__",
        ".pytest_cache",
        ".mypy_cache",
        ".tox",
        "dist",
        "build",
        ".DS_Store",
    }
    return any(part in excluded_names for part in parts) or path.suffix in {".pyc", ".pyo"}


def package_project(project_dir, output_dir):
    output_dir.mkdir(parents=True, exist_ok=True)
    artifact = output_dir / "deployment_package.zip"
    if artifact.exists():
        artifact.unlink()

    with zipfile.ZipFile(artifact, "w", compression=zipfile.ZIP_DEFLATED) as zf:
        for file_path in project_dir.rglob("*"):
            if file_path.is_dir():
                continue
            if file_path == artifact:
                continue
            if should_exclude(file_path.relative_to(project_dir)):
                continue
            zf.write(file_path, file_path.relative_to(project_dir))

    print(f"Created package: {artifact}")
    return artifact


def main():
    parser = argparse.ArgumentParser(description="Simple CI/CD deployment automation")
    parser.add_argument("--project-dir", default=".", help="Project directory")
    parser.add_argument("--output-dir", default="dist", help="Output directory for deployment package")
    args = parser.parse_args()

    project_dir = Path(args.project_dir).resolve()
    output_dir = Path(args.output_dir).resolve()

    install_dependencies(project_dir)
    run_tests(project_dir)
    package_project(project_dir, output_dir)


if __name__ == "__main__":
    main()